import{_ as t,o,c as n,a1 as r}from"./chunks/framework.DdbKPUhY.js";const m=JSON.parse('{"title":"✦ GenP Guide","description":"","frontmatter":{},"headers":[],"relativePath":"genp.md","filePath":"genp.md"}'),a={name:"genp.md"};function s(i,e,l,d,g,p){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="✦-genp-guide" tabindex="-1">✦ GenP Guide <a class="header-anchor" href="#✦-genp-guide" aria-label="Permalink to &quot;✦ GenP Guide&quot;">​</a></h1><p>Easily download and patch the latest version of any Creative Cloud software on <strong>Windows</strong> using <strong>GenP</strong>, an unlimited selection of apps, faster updates, and other benefits.</p><div style="background-color:#302e2e;padding:16px;border-radius:6px;"> ⓘ Mixing GenP with other methods on your machine is <strong>not recommended</strong>, as it will inevitably lead to issues. Run <a href="file:///C:/Path/To/Your/Folder/AdobeCreativeCloudCleanerTool.exe"> Adobe&#39;s Creative Cloud Cleaner Tool </a> to completely remove previous Adobe apps if this warning applies to you. </div><hr><ol><li>Download <a href="https://helpx.adobe.com/download-install/apps/download-install-apps/creative-cloud-apps/download-creative-cloud-desktop-app-from-web.html" target="_blank" rel="noreferrer">Adobe Creative Cloud</a>. You must create an account and sign in. Feel free to use a temporary email. Do <strong>not</strong> install Adobe Genuine Service (AGS) <em>if prompted</em>.</li><li>Go to <strong>Menu</strong> &gt; <strong>File</strong> &gt; <strong>Preferences</strong> and in the <strong>General</strong> tab, disable the following settings:</li></ol><div class="indent"><p><em>Launch Creative Cloud at login</em></p><p><em>Run Creative Cloud in the background after closing</em></p><p><em>Automatically keep Creative Cloud up to date</em></p></div><ol start="3"><li>Close <strong>Creative Cloud</strong> once finished. <em>(<strong>Menu</strong> &gt; <strong>File</strong> &gt; <strong>Quit Creative Cloud</strong>)</em></li><li>Download GenP from the <a href="https://gen.paramore.su/" target="_blank" rel="noreferrer">official GenP website</a>. The Binary download is recommended for beginners as it’s ready to use, while source is intended for more advanced users. <span class="note">Windows Defender, along with certain third-party programs, are known to wrongfully block GenP. You must whitelist or exclude the file. You may also disable real-time protection completely, but do not forget to turn it back on afterwards.</span></li><li>Right-click the zip &gt; <strong>Extract all</strong> <em>(GenP.vX.X.X-CGP.zip)</em> and <strong>Run GenP</strong> <em>(GenP-vX.X.X.exe)</em> <strong>as administrator</strong>.</li><li>In the main tab, click <strong>Search</strong>. You should be prompted three files underneath <strong>Creative Cloud</strong>, ensure that all three are selected and click <strong>Patch</strong>.</li><li>Open <strong>Creative Cloud</strong> and install your desired applications <em>(Premiere, After Effects, and so on)</em> in the <strong>Apps</strong> menu. Once the applications are installed, close <strong>Creative Cloud</strong> and all respective <strong>Adobe</strong> apps.</li><li><strong>Run GenP</strong> <em>(GenP-vX.X.X.exe)</em> <strong>as administrator</strong> and click <strong>Search</strong>. This time, select the files for your program(s) <em>(Premiere, After Effects, etc)</em> and click <strong>Patch</strong>. The application will now be patched, enjoy.</li></ol><p><span class="note">Websites such as <a href="https://lemmy.dbzer0.com/c/GenP" target="_blank" rel="noreferrer">lemmy.dbzer0.com/c/GenP</a> are <em><strong>unofficial</strong></em>, but can act as an answer key for beginners, as they cover potential errors and compatabilty information. Only ever download GenP from <a href="https://gen.paramore.su/" target="_blank" rel="noreferrer">gen.paramore.su</a>, their official domain.</span></p>',8)])])}const u=t(a,[["render",s]]);export{m as __pageData,u as default};
